using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id values from "EntityType|Key" (e.g. "Product|123") to just the key.
            // Existing documents use the compound format; this preserves it so point-reads still work.
            entity.HasRootDiscriminatorInJsonId(true);

            // HasIndex throws at startup in EF Core 9 Cosmos provider.
            // Cosmos DB indexing is managed via the container's indexing policy (Azure Portal / Bicep / Terraform).
            // Removed: entity.HasIndex(p => p.Sku);
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } = null!; }

